transform_js:
var questions = rawData.rows.map(function(r) { return r.q; });
var sd = rawData.rows.map(function(r) { return r.sd; });
var d = rawData.rows.map(function(r) { return r.d; });
var a = rawData.rows.map(function(r) { return r.a; });
var sa = rawData.rows.map(function(r) { return r.sa; });
transformedData = { questions: questions, sd: sd, d: d, a: a, sa: sa };

echarts_js:
option = {
  title: { text: 'Survey Results (Diverging)', left: 'center' },
  tooltip: { trigger: 'axis', axisPointer: { type: 'shadow' } },
  legend: { bottom: '3%', data: ['Strongly Disagree', 'Disagree', 'Agree', 'Strongly Agree'] },
  grid: { left: '25%', right: '5%', bottom: '15%' },
  yAxis: { type: 'category', data: transformedData.questions },
  xAxis: { type: 'value' },
  series: [
    { name: 'Disagree', type: 'bar', stack: 'survey', data: transformedData.d, itemStyle: { color: '#e67e73' } },
    { name: 'Strongly Disagree', type: 'bar', stack: 'survey', data: transformedData.sd, itemStyle: { color: '#c0392b' } },
    { name: 'Agree', type: 'bar', stack: 'survey', data: transformedData.a, itemStyle: { color: '#73c0de' } },
    { name: 'Strongly Agree', type: 'bar', stack: 'survey', data: transformedData.sa, itemStyle: { color: '#3498db' } }
  ]
};
